<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Agricultural Drone-Advanced Cat Sight Algorithm Simulation</title><script src="https://cdn.tailwindcss.com"></script><script src="https://cdnjs.cloudflare.com/ajax/libs/three.js/r128/three.min.js"></script><script src="https://cdn.jsdelivr.net/npm/three@0.128.0/examples/js/controls/OrbitControls.js"></script><script src="https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.5/gsap.min.js"></script><link rel="preconnect" href="https://fonts.googleapis.com"><link rel="preconnect" href="https://fonts.gstatic.com" crossorigin><link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;700&display=swap" rel="stylesheet"><link rel="stylesheet" href="arrogant.css"><style>body{margin:0;overflow:hidden;font-family:'Inter',sans-serif;background-color:#f5f5f5}
#container{width:100vw;height:100vh;display:block}
#controls{position:absolute;bottom:20px;left:50%;transform:translateX(-50%);background-color:rgba(50,50,50,0.9);padding:20px;border-radius:12px;display:flex;flex-direction:column;gap:12px;align-items:center;max-width:600px;width:90%;box-shadow:0 8px 16px rgba(0,0,0,0.5);transition:opacity 0.3s ease,transform 0.3s ease;color:#f0f0f0}
#controls.hidden{opacity:0;transform:translateX(-50%)translateY(20px);pointer-events:none}
button{background-color:#2E7D32;border:none;color:white;padding:10px 18px;text-align:center;font-size:14px;border-radius:8px;cursor:pointer;transition:background-color 0.3s,transform 0.2s}
button:hover{background-color:#1B5E20;transform:scale(1.05)}
button:disabled{background-color:#999;cursor:not-allowed}
#toggleControlsBtn{position:absolute;bottom:10px;left:50%;transform:translateX(-50%);background-color:#1565C0;padding:10px 18px;border-radius:8px;z-index:1000}
#toggleControlsBtn:hover{background-color:#0D47A1}
#targetInfo,#statusInfo,#plantInfo,#errorInfo,#modeDescription,#soilInfo{color:#f0f0f0;font-size:13px;text-align:center}.info-panel{background-color:rgba(255,255,255,0.08);padding:10px;border-radius:8px;width:100%}
#modeSelect{background-color:#424242;color:white;padding:8px;border-radius:6px;font-size:14px;width:100%}
#errorInfo{color:#e53935;font-weight:bold}
#progressBar{width:100%;height:8px;background-color:#555;border-radius:5px;overflow:hidden}
#progressFill{height:100%;background-color:#43A047;width:0%;transition:width 0.3s}
#heatmapCanvas{position:absolute;top:10px;right:10px;border:2px solid #555;border-radius:8px}</style><script>function toggleControls(){const controls=document.getElementById('controls');const toggleBtn=document.getElementById('toggleControlsBtn');controls.classList.toggle('hidden');toggleBtn.textContent=controls.classList.contains('hidden')?'Show Controls':'Hide Controls'}</script></head><body><div id="container"></div><canvas id="heatmapCanvas" width="200" height="200"></canvas><button id="toggleControlsBtn" onclick="toggleControls()">Hide Controls</button><div id="controls"><div class="info-panel"><span id="targetInfo">Target:1/200</span></div><div class="info-panel"><span id="plantInfo">Plant:None</span></div><div class="info-panel"><span id="soilInfo">Soil:None</span></div><div class="info-panel"><span id="statusInfo">Status:Initializing</span></div><div class="info-panel"><span id="modeDescription">Mode:Scan-Scanning field targets</span></div><div class="info-panel" style="display: none;"><span id="errorInfo"></span></div><div class="info-panel"><div id="progressBar"><div id="progressFill"></div></div></div><div class="flex gap-3 flex-wrap justify-center"><button id="prevBtn">Previous Target</button><button id="nextBtn">Next Target</button><button id="autoBtn">Toggle Auto Mode</button><button id="weatherBtn">Toggle Weather</button><button id="sprayBtn">Toggle Fertilizer Spray</button><button id="resetBtn">Reset Simulation</button><button id="cameraFollowBtn">Toggle Camera Follow</button><button id="perfModeBtn">Toggle Performance Mode</button></div><select id="modeSelect"><option value="scan">Scan Mode</option><option value="identify">Plant Identification</option><option value="obstacle">Obstacle Avoidance</option><option value="spray">Fertilizer Spray</option><option value="soil">Soil Analysis</option><option value="pest">Pest Detection</option><option value="irrigation">Irrigation Planning</option><option value="growth">Crop Growth Monitoring</option></select></div><div id="csaPanel" class="fixed top-10 left-10 bg-gray-800 text-white p-4 rounded-lg max-w-sm"><h3 class="text-lg font-bold">CSA Status</h3><p id="csaAction">Current Action:Initializing</p><p id="csaRole">CSA Role:Setting up target angles</p><p id="csaDetails">Details:Awaiting drone movement</p></div><script>let scene,camera,renderer,controls;let drone,ground,water,grassInstances,targetPoints=[],obstacles=[],plants=[],trees=[],birds=[],targetLine,scanCircle,fertilizerSpray;let currentTargetIndex=0;let autoMode=!1;let cameraFollow=!1;let currentMode='scan';let weatherActive=!1;let sprayActive=!1;let performanceMode=!1;const numTargets=200;const numObstacles=150;const numPlants=5000;const numGrassBlades=111500;const numTrees=0;const numBirds=20;const fieldRadius=50;const waterRadius=100;const droneAltitude=3;const droneSpeed=4.05;const cameraOffset=new THREE.Vector3(0,3,8);let droneTargetPosition=new THREE.Vector3(0,droneAltitude,0);let isAnimating=!1;let rainParticles,windDirection=new THREE.Vector3(0,0,0);let lastFrameTime=performance.now();let fpsCounter=0;let fpsSum=0;let lowFpsWarning=!1;function monitorPerformance(){const now=performance.now();const delta=now-lastFrameTime;if(delta>0){const fps=1000/delta;fpsCounter++;fpsSum+=fps;if(fpsCounter>=30){const avgFps=fpsSum/fpsCounter;if(avgFps<20&&!lowFpsWarning){lowFpsWarning=!0;document.getElementById('errorInfo').innerText='Warning: Low FPS detected. Enable Performance Mode to improve stability.';updateCSAPanel('Performance Warning','Low FPS detected','Consider enabling Performance Mode')}else if(avgFps>=30){lowFpsWarning=!1}
fpsCounter=0;fpsSum=0}}
lastFrameTime=now}
window.onerror=function(msg,url,lineNo,columnNo,error){const errorMessage=`Error: ${msg} at ${url}:${lineNo}:${columnNo}\nStack: ${error?.stack || 'No stack trace'}`;console.error(errorMessage);document.getElementById('errorInfo').innerText='Critical Error: Simulation halted. Check console for details.';updateCSAPanel('Critical Error','Simulation failed',msg);return!1};class CatSightAlgorithm{constructor(targets,plants){this.targets=targets;this.plants=plants;this.angleMap=new Map();this.pestMap=new Map();this.moistureMap=new Map();this.growthMap=new Map();try{this.initializeMappings()}catch(e){throw new Error(`CSA initialization failed: ${e.message}`)}}
initializeMappings(){this.targets.forEach((target,index)=>{const angle=this.getAngleForTarget(index,this.targets.length);this.angleMap.set(target.userData.id,angle)});const startTime=performance.now();this.plants.forEach(plant=>{if(performance.now()-startTime>5000){throw new Error('Plant mapping timed out')}
const pestScore=Math.random();const moistureScore=Math.random();const growthStage=Math.floor(Math.random()*3);this.pestMap.set(plant.userData.id,pestScore);this.moistureMap.set(plant.userData.id,moistureScore);this.growthMap.set(plant.userData.id,growthStage)})}
getAngleForTarget(index,totalTargets){return(index/totalTargets)*360}
getPositionOnCircle(radius,angleDegrees){const angleRadians=THREE.MathUtils.degToRad(angleDegrees);return new THREE.Vector3(radius*Math.cos(angleRadians),0,radius*Math.sin(angleRadians))}
queryTarget(targetId){if(this.angleMap.has(targetId)){return this.angleMap.get(targetId)}
let minDiff=Infinity;let nearestAngle=0;this.angleMap.forEach((angle,id)=>{const diff=Math.abs(targetId-id);if(diff<minDiff){minDiff=diff;nearestAngle=angle}});return nearestAngle}
queryPestScore(plant){return this.pestMap.get(plant.userData.id)||0}
queryMoistureScore(plant){return this.moistureMap.get(plant.userData.id)||0}
queryGrowthStage(plant){const stage=this.growthMap.get(plant.userData.id)||0;return['Seedling','Vegetative','Flowering'][stage]}
updateTargets(newTargets){this.targets=newTargets;this.initializeMappings()}}
class PlantIdentification{constructor(plants){this.plants=plants;this.types=['Wheat','Corn','Soybean','Weed'];this.healthMap=new Map();this.canvas=document.getElementById('heatmapCanvas');this.ctx=this.canvas.getContext('2d');try{this.initializeHealth()}catch(e){throw new Error(`Plant identification initialization failed: ${e.message}`)}}
initializeHealth(){const startTime=performance.now();this.plants.forEach(plant=>{if(performance.now()-startTime>5000){throw new Error('Health mapping timed out')}
const health=Math.random();this.healthMap.set(plant.userData.id,health)});this.updateHeatmap('health')}
identifyPlant(plant){const index=plant.userData.id%this.types.length;const health=this.healthMap.get(plant.userData.id);return{type:this.types[index],health:health>0.5?'Healthy':'Unhealthy',healthScore:health.toFixed(2),confidence:(0.8+Math.random()*0.2).toFixed(2)}}
updateHeatmap(mode,dataMap){try{this.ctx.clearRect(0,0,this.canvas.width,this.canvas.height);const sampleSize=Math.min(1000,this.plants.length);const step=Math.floor(this.plants.length/sampleSize);for(let i=0;i<this.plants.length;i+=step){const plant=this.plants[i];let value;if(mode==='health')value=this.healthMap.get(plant.userData.id);else if(mode==='pest')value=dataMap.get(plant.userData.id);else if(mode==='moisture')value=dataMap.get(plant.userData.id);else if(mode==='growth')value=dataMap.get(plant.userData.id)/2;const x=((plant.position.x+fieldRadius)/(fieldRadius*2))*this.canvas.width;const y=((plant.position.z+fieldRadius)/(fieldRadius*2))*this.canvas.height;this.ctx.beginPath();this.ctx.arc(x,y,5,0,Math.PI*2);this.ctx.fillStyle=`hsl(${value * 120}, 100%, 50%)`;this.ctx.fill()}}catch(e){console.error(`Heatmap update failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to update heatmap.';updateCSAPanel('Heatmap Error','Failed to update heatmap',e.message)}}}
class SoilAnalysis{constructor(plants){this.plants=plants;this.moistureMap=new Map();try{this.initializeMoisture()}catch(e){throw new Error(`Soil analysis initialization failed: ${e.message}`)}}
initializeMoisture(){const startTime=performance.now();this.plants.forEach(plant=>{if(performance.now()-startTime>5000){throw new Error('Moisture mapping timed out')}
const moisture=Math.random();this.moistureMap.set(plant.userData.id,moisture)})}
analyzeSoil(plant){const moisture=this.moistureMap.get(plant.userData.id);return{moistureLevel:moisture>0.6?'Optimal':moisture>0.3?'Moderate':'Low',moistureScore:moisture.toFixed(2),recommendation:moisture>0.6?'No irrigation needed':moisture>0.3?'Monitor closely':'Irrigate immediately'}}}
class PestDetection{constructor(plants,csa){this.plants=plants;this.csa=csa}
detectPests(plant){const pestScore=this.csa.queryPestScore(plant);return{pestLevel:pestScore>0.7?'High':pestScore>0.4?'Moderate':'Low',pestScore:pestScore.toFixed(2),action:pestScore>0.7?'Apply pesticide':pestScore>0.4?'Monitor':'No action needed'}}}
class IrrigationPlanning{constructor(plants,csa){this.plants=plants;this.csa=csa}
planIrrigation(plant){const moistureScore=this.csa.queryMoistureScore(plant);return{moistureLevel:moistureScore>0.6?'Optimal':moistureScore>0.3?'Moderate':'Low',moistureScore:moistureScore.toFixed(2),irrigationNeed:moistureScore>0.6?'None':moistureScore>0.3?'Low':'High'}}}
class GrowthMonitoring{constructor(plants,csa){this.plants=plants;this.csa=csa}
monitorGrowth(plant){const stage=this.csa.queryGrowthStage(plant);const health=plantIdentifier.healthMap.get(plant.userData.id);return{growthStage:stage,healthImpact:health>0.5?'Positive':'Negative',recommendation:stage==='Seedling'?'Ensure adequate water':stage==='Vegetative'?'Apply nutrients':'Prepare for harvest'}}}
class ObstacleAvoidance{constructor(obstacles,drone){this.obstacles=obstacles;this.drone=drone;this.gridSize=1;this.gridWidth=Math.ceil(fieldRadius*2/this.gridSize);this.safeDistance=2}
findSafePath(start,end){try{const startTime=performance.now();const grid=this.createGrid();const startNode=this.worldToGrid(start);const endNode=this.worldToGrid(end);const path=this.aStar(startNode,endNode,grid,startTime);return path.map(node=>this.gridToWorld(node))}catch(e){console.error(`Pathfinding failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Pathfinding failed. Using direct path.';updateCSAPanel('Pathfinding Error','A* algorithm failed',e.message);return[start,end]}}
createGrid(){const grid=Array(this.gridWidth).fill().map(()=>Array(this.gridWidth).fill(0));this.obstacles.forEach(obstacle=>{const{x,z}=this.worldToGrid(obstacle.position);for(let dx=-1;dx<=1;dx++){for(let dz=-1;dz<=1;dz++){const nx=x+dx;const nz=z+dz;if(nx>=0&&nx<this.gridWidth&&nz>=0&&nz<this.gridWidth){grid[nx][nz]=1}}}});return grid}
