aStar(start,goal,grid,startTime){const openSet=[start];const closedSet=new Set();const gScore=new Map();const fScore=new Map();const cameFrom=new Map();gScore.set(`${start.x},${start.z}`,0);fScore.set(`${start.x},${start.z}`,this.heuristic(start,goal));while(openSet.length>0){if(performance.now()-startTime>3000){throw new Error('A* pathfinding timed out')}
let current=openSet.reduce((a,b)=>fScore.get(`${a.x},${a.z}`)<fScore.get(`${b.x},${b.z}`)?a:b);if(current.x===goal.x&&current.z===goal.z){return this.reconstructPath(cameFrom,current)}
openSet.splice(openSet.indexOf(current),1);closedSet.add(`${current.x},${current.z}`);const neighbors=this.getNeighbors(current,grid);for(const neighbor of neighbors){if(closedSet.has(`${neighbor.x},${neighbor.z}`))continue;const tentativeGScore=gScore.get(`${current.x},${current.z}`)+1;if(!openSet.some(n=>n.x===neighbor.x&&n.z===neighbor.z)){openSet.push(neighbor)}else if(tentativeGScore>=gScore.get(`${neighbor.x},${neighbor.z}`)){continue}
cameFrom.set(`${neighbor.x},${neighbor.z}`,current);gScore.set(`${neighbor.x},${neighbor.z}`,tentativeGScore);fScore.set(`${neighbor.x},${neighbor.z}`,tentativeGScore+this.heuristic(neighbor,goal))}}
return[this.gridToWorld(start),this.gridToWorld(goal)]}
heuristic(a,b){return Math.abs(a.x-b.x)+Math.abs(a.z-b.z)}
getNeighbors(node,grid){const neighbors=[];const directions=[{x:0,z:1},{x:0,z:-1},{x:1,z:0},{x:-1,z:0}];for(const dir of directions){const nx=node.x+dir.x;const nz=node.z+dir.z;if(nx>=0&&nx<this.gridWidth&&nz>=0&&nz<this.gridWidth&&grid[nx][nz]===0){neighbors.push({x:nx,z:nz})}}
return neighbors}
reconstructPath(cameFrom,current){const path=[current];while(cameFrom.has(`${current.x},${current.z}`)){current=cameFrom.get(`${current.x},${current.z}`);path.unshift(current)}
return path}}
class AnimationManager{constructor(){this.animations=[]}
addAnimation(object,properties,duration,config={}){try{const animation=gsap.to(object,{duration:duration/1000,...properties,ease:config.easing||"power2.inOut",onUpdate:config.onUpdate,onComplete:()=>{this.animations=this.animations.filter(a=>a!==animation);if(config.onComplete)config.onComplete();}});this.animations.push(animation);return animation}catch(e){console.error(`Animation creation failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to create animation.';updateCSAPanel('Animation Error','Failed to create animation',e.message)}}
