t.set(10,10);groundMaterial.map=texture;groundMaterial.needsUpdate=!0},undefined,(error)=>{console.error('Failed to load primary ground texture:',error);document.getElementById('errorInfo').innerText='Error: Failed to load primary ground texture. Trying fallback...';textureLoader.load(fallbackGroundTextureUrl,(texture)=>{texture.wrapS=texture.wrapT=THREE.RepeatWrapping;texture.repeat.set(10,10);groundMaterial.map=texture;groundMaterial.needsUpdate=!0},undefined,(fallbackError)=>{console.error('Failed to load fallback ground texture:',fallbackError);document.getElementById('errorInfo').innerText='Error: Failed to load ground texture. Using solid color.';groundMaterial.map=null;groundMaterial.color.setHex(0x8B4513);groundMaterial.needsUpdate=!0})});const grassGeometry=new THREE.PlaneGeometry(0.05,1.5);const grassMaterial=new THREE.MeshStandardMaterial({color:0x228B22,side:THREE.DoubleSide});const grassInstance=new THREE.InstancedMesh(grassGeometry,grassMaterial,numGrassBlades);const dummy=new THREE.Object3D();for(let i=0;i<numGrassBlades;i++){const angle=Math.random()*Math.PI*2;const radius=Math.random()*fieldRadius*0.9;dummy.position.set(radius*Math.cos(angle),0.75,radius*Math.sin(angle));dummy.rotation.y=Math.random()*Math.PI*2;dummy.scale.setScalar(0.8+Math.random()*0.4);dummy.updateMatrix();grassInstance.setMatrixAt(i,dummy.matrix)}
grassInstance.castShadow=!performanceMode;grassInstance.receiveShadow=!performanceMode;scene.add(grassInstance);grassInstances=grassInstance;const waterGeometry=new THREE.RingGeometry(fieldRadius,waterRadius,32);const waterMaterial=new THREE.MeshStandardMaterial({color:0x4682B4,transparent:!0,opacity:0.7,side:THREE.DoubleSide});textureLoader.load('https://raw.githubusercontent.com/mrdoob/three.js/dev/examples/textures/water/Water_1_M_Normal.jpg',(texture)=>{texture.wrapS=texture.wrapT=THREE.RepeatWrapping;texture.repeat.set(4,4);waterMaterial.map=texture;waterMaterial.needsUpdate=!0},undefined,(error)=>{console.error('Failed to load primary water texture:',error);document.getElementById('errorInfo').innerText='Error: Failed to load primary water texture. Trying fallback...';textureLoader.load('https://raw.githubusercontent.com/mrdoob/three.js/dev/examples/textures/water/Water_2_M_Normal.jpg',(texture)=>{texture.wrapS=texture.wrapT=THREE.RepeatWrapping;texture.repeat.set(4,4);waterMaterial.map=texture;waterMaterial.needsUpdate=!0},undefined,(fallbackError)=>{console.error('Failed to load fallback water texture:',fallbackError);document.getElementById('errorInfo').innerText='Error: Failed to load water texture. Using solid color.';waterMaterial.map=null;waterMaterial.color.setHex(0x4682B4);waterMaterial.needsUpdate=!0})});water=new THREE.Mesh(waterGeometry,waterMaterial);water.rotation.x=-Math.PI/2;water.position.y=-0.1;water.receiveShadow=!performanceMode;scene.add(water);const treeTrunkGeo=new THREE.CylinderGeometry(0.5,0.5,5,8);const treeFoliageGeo=new THREE.SphereGeometry(2,8,8);const treeTrunkMat=new THREE.MeshStandardMaterial({color:0x4A3728});const treeFoliageMat=new THREE.MeshStandardMaterial({color:0x2E7D32});for(let i=0;i<numTrees;i++){const angle=Math.random()*360;const radius=fieldRadius*(0.8+Math.random()*0.2);const position=new THREE.Vector3(radius*Math.cos(THREE.MathUtils.degToRad(angle)),2.5,radius*Math.sin(THREE.MathUtils.degToRad(angle)));const trunk=new THREE.Mesh(treeTrunkGeo,treeTrunkMat);trunk.position.copy(position);trunk.castShadow=!performanceMode;trunk.receiveShadow=!performanceMode;scene.add(trunk);const foliage=new THREE.Mesh(treeFoliageGeo,treeFoliageMat);foliage.position.set(position.x,position.y+3,position.z);foliage.castShadow=!performanceMode;foliage.receiveShadow=!performanceMode;scene.add(foliage);trees.push({trunk,foliage,userData:{id:i,type:'tree'}});obstacles.push(trunk)}
const birdGeo=new THREE.ConeGeometry(0.2,0.4,4);const birdMat=new THREE.MeshStandardMaterial({color:0x78909C});for(let i=0;i<numBirds;i++){const bird=new THREE.Mesh(birdGeo,birdMat);const angle=Math.random()*360;const radius=fieldRadius*(0.5+Math.random()*0.5);bird.position.set(radius*Math.cos(THREE.MathUtils.degToRad(angle)),5+Math.random()*5,radius*Math.sin(THREE.MathUtils.degToRad(angle)));bird.castShadow=!performanceMode;bird.userData={id:i,type:'bird',velocity:new THREE.Vector3((Math.random()-0.5)*0.1,0,(Math.random()-0.5)*0.1)};scene.add(bird);birds.push(bird)}
