function togglePerformanceMode(){performanceMode=!performanceMode;document.getElementById('perfModeBtn').textContent=performanceMode?'Disable Performance Mode':'Enable Performance Mode';try{renderer.shadowMap.enabled=!performanceMode;ground.receiveShadow=!performanceMode;grassInstances.castShadow=!performanceMode;grassInstances.receiveShadow=!performanceMode;water.receiveShadow=!performanceMode;trees.forEach(tree=>{tree.trunk.castShadow=!performanceMode;tree.trunk.receiveShadow=!performanceMode;tree.foliage.castShadow=!performanceMode;tree.foliage.receiveShadow=!performanceMode});birds.forEach(bird=>bird.castShadow=!performanceMode);drone.children[0].castShadow=!performanceMode;drone.children[0].children.forEach(child=>child.castShadow=!performanceMode);targetPoints.forEach(target=>target.castShadow=!performanceMode);obstacles.forEach(obstacle=>obstacle.castShadow=!performanceMode);plants.forEach(plant=>plant.castShadow=!performanceMode);rainParticles.geometry.setAttribute('position',new THREE.Float32BufferAttribute(new Float32Array((performanceMode?1000:5000)*3).fill(0),3));fertilizerSpray.geometry.setAttribute('position',new THREE.Float32BufferAttribute(new Float32Array((performanceMode?500:2000)*3).fill(0),3));updateCSAPanel('Performance Mode',`Toggled to ${performanceMode ? 'low' : 'high'} resource usage`,'Shadows and particle counts adjusted')}catch(e){console.error(`Performance mode toggle failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to toggle performance mode.';updateCSAPanel('Performance Mode Error','Failed to adjust settings',e.message)}
