function updateTargetVisualization(){try{if(targetPoints.length===0)return;targetPoints.forEach(tp=>{tp.material.color.setHex(tp.userData.originalColor)});plants.forEach(p=>{p.material.color.setHex(0x228B22)});const target=targetPoints[currentTargetIndex];const targetAngle=catSightAlgo.queryTarget(target.userData.id);target.material.color.setHex(0xff0000);const angleToTargetRad=Math.atan2(target.position.z,target.position.x);drone.rotation.y=-angleToTargetRad+Math.PI/2;updateTargetLine();let plantInfo='Plant: None';let soilInfo='Soil: None';let csaDetails=`Target angle: ${targetAngle.toFixed(1)}°`;if(currentMode==='identify'){const closestPlant=findClosestPlant();if(closestPlant){const info=plantIdentifier.identifyPlant(closestPlant);plantInfo=`Plant: ${info.type}, Health: ${info.health} (${info.healthScore}), Confidence: ${info.confidence}`;closestPlant.material.color.setHex(0x00ff00);csaDetails=`CSA identified plant type with confidence ${info.confidence}`;plantIdentifier.updateHeatmap('health')}}else if(currentMode==='soil'){const closestPlant=findClosestPlant();if(closestPlant){const info=soilAnalyzer.analyzeSoil(closestPlant);soilInfo=`Soil: Moisture ${info.moistureLevel} (${info.moistureScore}), Recommendation: ${info.recommendation}`;closestPlant.material.color.setHex(0x00ff00);csaDetails=`CSA analyzed soil moisture: ${info.moistureScore}`;plantIdentifier.updateHeatmap('moisture',catSightAlgo.moistureMap)}}else if(currentMode==='spray'){fertilizerSpray.visible=sprayActive;const closestPlant=findClosestPlant();if(closestPlant&&sprayActive){plantInfo=`Spraying: ${plantIdentifier.identifyPlant(closestPlant).type}`;csaDetails=`CSA targeting plant for fertilizer application`}}else if(currentMode==='pest'){const closestPlant=findClosestPlant();if(closestPlant){const info=pestDetector.detectPests(closestPlant);plantInfo=`Pests: ${info.pestLevel} (${info.pestScore}), Action: ${info.action}`;closestPlant.material.color.setHex(0xff0000);csaDetails=`CSA pest score: ${info.pestScore}, recommending ${info.action}`;plantIdentifier.updateHeatmap('pest',catSightAlgo.pestMap)}}else if(currentMode==='irrigation'){const closestPlant=findClosestPlant();if(closestPlant){const info=irrigationPlanner.planIrrigation(closestPlant);soilInfo=`Irrigation: ${info.moistureLevel} (${info.moistureScore}), Need: ${info.irrigationNeed}`;closestPlant.material.color.setHex(0x0000ff);csaDetails=`CSA moisture score: ${info.moistureScore}, irrigation need: ${info.irrigationNeed}`;plantIdentifier.updateHeatmap('moisture',catSightAlgo.moistureMap)}}else if(currentMode==='growth'){const closestPlant=findClosestPlant();if(closestPlant){const info=growthMonitor.monitorGrowth(closestPlant);plantInfo=`Growth: ${info.growthStage}, Health: ${info.healthImpact}, Recommendation: ${info.recommendation}`;closestPlant.material.color.setHex(0xffff00);csaDetails=`CSA growth stage: ${info.growthStage}, health impact: ${info.healthImpact}`;plantIdentifier.updateHeatmap('growth',catSightAlgo.growthMap)}}
document.getElementById('targetInfo').innerText=`Target: ${currentTargetIndex + 1} / ${numTargets} (Angle: ${targetAngle.toFixed(1)}°)`;document.getElementById('plantInfo').innerText=plantInfo;document.getElementById('soilInfo').innerText=soilInfo;document.getElementById('progressFill').style.width=`${((currentTargetIndex + 1) / numTargets * 100)}%`;updateStatus();updateCSAPanel(`Processing target ${currentTargetIndex + 1}`,`CSA guiding drone in ${currentMode} mode`,csaDetails)}catch(e){console.error(`Target visualization failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to update visualization.';updateCSAPanel('Visualization Error','Failed to update target visualization',e.message)}}
function updateTargetLine(){try{const target=targetPoints[currentTargetIndex];const linePositions=targetLine.geometry.attributes.position.array;linePositions[0]=drone.position.x;linePositions[1]=drone.position.y;linePositions[2]=drone.position.z;linePositions[3]=target.position.x;linePositions[4]=target.position.y;linePositions[5]=target.position.z;targetLine.geometry.attributes.position.needsUpdate=!0;targetLine.visible=!0}catch(e){console.error(`Target line update failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to update target line.';updateCSAPanel('Target Line Error','Failed to update target line',e.message)}}
function findClosestPlant(){try{let closest=null;let minDist=Infinity;const sampleSize=Math.min(1000,plants.length);const step=Math.floor(plants.length/sampleSize);for(let i=0;i<plants.length;i+=step){const plant=plants[i];const dist=drone.position.distanceTo(plant.position);if(dist<minDist&&dist<5){minDist=dist;closest=plant}}
return closest}catch(e){console.error(`Closest plant search failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to find closest plant.';updateCSAPanel('Plant Search Error','Failed to find closest plant',e.message);return null}}
function updateStatus(){try{let status=`Mode: ${currentMode.charAt(0).toUpperCase() + currentMode.slice(1)}`;if(autoMode)status+=', Auto Mode: ON';else status+=', Auto Mode: OFF';if(weatherActive)status+=', Weather: ON';else status+=', Weather: OFF';if(sprayActive)status+=', Spray: ON';else status+=', Spray: OFF';if(cameraFollow)status+=', Camera Follow: ON';else status+=', Camera Follow: OFF';if(performanceMode)status+=', Performance Mode: ON';else status+=', Performance Mode: OFF';if(isAnimating)status+=', Moving...';document.getElementById('statusInfo').innerText=status}catch(e){console.error(`Status update failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to update status.';updateCSAPanel('Status Error','Failed to update status',e.message)}}
function updateModeDescription(){try{const descriptions={scan:'Mode: Scan - Scanning field targets in a predefined pattern using CSA.',identify:'Mode: Identify - Analyzing plants for type and health status with CSA.',obstacle:'Mode: Obstacle - Navigating around obstacles using A* pathfinding and CSA.',spray:'Mode: Spray - Applying fertilizer precisely with CSA-driven targeting.',soil:'Mode: Soil - Analyzing soil moisture levels with CSA for irrigation planning.',pest:'Mode: Pest - Detecting pest infestations with CSA-driven prioritization.',irrigation:'Mode: Irrigation - Planning irrigation based on CSA moisture mapping.',growth:'Mode: Growth - Monitoring crop growth stages with CSA analysis.'};document.getElementById('modeDescription').innerText=descriptions[currentMode]}catch(e){console.error(`Mode description update failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to update mode description.';updateCSAPanel('Mode Description Error','Failed to update mode description',e.message)}}
function updateCSAPanel(action,role,details){try{document.getElementById('csaAction').innerText=`Current Action: ${action}`;document.getElementById('csaRole').innerText=`CSA Role: ${role}`;document.getElementById('csaDetails').innerText=`Details: ${details}`}catch(e){console.error(`CSA panel update failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to update CSA panel.'}}
function animate(){try{requestAnimationFrame(animate);monitorPerformance();const time=Date.now()*0.001;drone.position.y=droneTargetPosition.y+Math.sin(time*2)*0.1;drone.children[0].children.forEach((child,i)=>{if(i>=1&&i<=4){child.rotation.y+=0.5}});if(water&&water.material.map&&!performanceMode){water.material.map.offset.x+=0.001;water.material.map.offset.y+=0.001}
if(grassInstances&&!performanceMode){const dummy=new THREE.Object3D();for(let i=0;i<numGrassBlades;i++){grassInstances.getMatrixAt(i,dummy.matrix);dummy.matrix.decompose(dummy.position,dummy.quaternion,dummy.scale);const windEffect=windDirection.x*0.3+windDirection.z*0.3;dummy.rotation.z=Math.sin(time*2+i*0.2)*0.15+windEffect;dummy.rotation.x=Math.cos(time*2+i*0.2)*0.1+windEffect*0.5;dummy.updateMatrix();grassInstances.setMatrixAt(i,dummy.matrix)}
grassInstances.instanceMatrix.needsUpdate=!0}
if(weatherActive&&rainParticles&&!performanceMode){const positions=rainParticles.geometry.attributes.position.array;for(let i=0;i<positions.length;i+=3){positions[i]+=windDirection.x*0.5;positions[i+1]-=0.2;positions[i+2]+=windDirection.z*0.5;if(positions[i+1]<0){positions[i+1]=20;positions[i]=Math.random()*fieldRadius*2-fieldRadius;positions[i+2]=Math.random()*fieldRadius*2-fieldRadius}}
rainParticles.geometry.attributes.position.needsUpdate=!0}
birds.forEach(bird=>{bird.position.add(bird.userData.velocity);bird.rotation.y=Math.atan2(bird.userData.velocity.z,bird.userData.velocity.x)+Math.PI/2;if(bird.position.distanceTo(new THREE.Vector3(0,0,0))>fieldRadius*1.5){bird.userData.velocity.multiplyScalar(-1)}
bird.position.y=5+Math.sin(time+bird.userData.id)*2});if(sprayActive&&currentMode==='spray'&&fertilizerSpray.visible){const positions=fertilizerSpray.geometry.attributes.position.array;const velocities=fertilizerSpray.userData.velocities;for(let i=0;i<positions.length;i+=3){positions[i]+=velocities[i/3*3]*0.05;positions[i+1]+=velocities[i/3*3+1]*0.05;positions[i+2]+=velocities[i/3*3+2]*0.05;if(positions[i+1]<-5||Math.abs(positions[i])>2||Math.abs(positions[i+2])>2){positions[i]=(Math.random()-0.5)*0.2;positions[i+1]=0;positions[i+2]=(Math.random()-0.5)*0.2;velocities[i/3*3]=(Math.random()-0.5)*0.5;velocities[i/3*3+1]=-Math.random()*2-1;velocities[i/3*3+2]=(Math.random()-0.5)*0.5}}
fertilizerSpray.geometry.attributes.position.needsUpdate=!0}
if(weatherActive){drone.position.add(windDirection);if(drone.position.x>fieldRadius)drone.position.x=fieldRadius;if(drone.position.x<-fieldRadius)drone.position.x=-fieldRadius;if(drone.position.z>fieldRadius)drone.position.z=fieldRadius;if(drone.position.z<-fieldRadius)drone.position.z=-fieldRadius}
if(cameraFollow){controls.enabled=!1;const droneDirection=new THREE.Vector3();drone.getWorldDirection(droneDirection);const desiredPosition=drone.position.clone().add(cameraOffset);camera.position.lerp(desiredPosition,0.1);camera.lookAt(drone.position);if(camera.position.y<1)camera.position.y=1}else{controls.enabled=!0;controls.update()}
renderer.render(scene,camera)}catch(e){console.error(`Animation loop failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Animation loop failed. Check console.';updateCSAPanel('Animation Loop Error','Failed to render frame',e.message)}}
try{init();animate()}catch(e){console.error(`Startup failed: ${e.message}`);document.getElementById('errorInfo').innerText='Error: Failed to start simulation. Check console.';updateCSAPanel('Startup Error','Failed to start simulation',e.message)}</script></body></html>